var e=[{id:`L2_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`큭……!`,JPN:`くっ……！`,ENG:`Khhk...!`,TWN:`咳……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아아, 가여워라.`,JPN:`ああ、かわいそう。`,ENG:`Oh, how pitiful.`,TWN:`哀哀，好慘。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`기껏 전력으로 싸워주게 됐는데, 벌써 지친 거야?`,JPN:`せっかく全力で戦ってあげようと思ったのに、もう疲れちゃったの？`,ENG:`I gave you the honor of fighting me at full power, but you're exhausted already?`,TWN:`難得我打得這麼認真，你這麼快就不行啦？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`사나에, 상처가……!`,JPN:`早苗、傷が……！`,ENG:`Sanae, your wound...!`,TWN:`早苗，你的傷口……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`당주님! 이쪽으로 오시면…… 안 됩니다.`,JPN:`ご当主様！　こちらに来ては……なりません。`,ENG:`Lady Nanahara! You must... stay back.`,TWN:`堂主！不可以……過來。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SOLDIER_NPC_UNION_NULL`,text:{KOREA:`유다님, 결계옥의 방출파장에 변화가 생겼습니다. 말씀하신 안정화단계에 다다른 듯합니다.`,JPN:`ユダ様、結界玉の放出波長に変化が見られます。おっしゃっていた安定化段階に至ったようです。`,ENG:`The barrier's wave frequency has changed, sir. I believe we are reaching the stabilization phase, just as you said.`,TWN:`報告，結界玉石的釋放波長發生變化，似乎已經到達您說的穩定化階段。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`SOLDIER_NPC_UNION_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`GENERAL_NPC_NOA_NULL`,text:{KOREA:`음, 이제 영혼과 그릇을 융합하는 과정만 남았군.`,JPN:`うむ、あとは魂と器を融合するだけか。`,ENG:`Hmm, now all that is left is for the soul and vessel to fuse into one.`,TWN:`嗯，接下來只剩下融合靈魂和器皿的過程。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GENERAL_NPC_NOA_NULL`,text:{KOREA:`레노어, 실험체를 데려와라. 방해되는 것들은 이제 처분해도 상관없다.`,JPN:`レノア、実験体を連れてこい。邪魔者はもう処分して構わない。`,ENG:`Lenore, bring me my test subject. You can do as you please with the others.`,TWN:`蕾諾雅，把實驗體帶過來，閒雜人等一律處理掉。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`네, 아버지.`,JPN:`はい、お父様。`,ENG:`Yes, father.`,TWN:`是，父親。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`들었지? 이제 너희는 쓸모가 없어졌어.`,JPN:`聞いた？　もうお前たちは用済みになったの。`,ENG:`Hear that? You're useless now.`,TWN:`聽到沒？現在你們已經無用武之處。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`살고 싶으면 옆으로 빌빌 기어서 꺼져버리지 그래?`,JPN:`生きたけりゃ脇にでも這っていってそのまま逃げれば？`,ENG:`How about you crawl aside if you want to live, hmm?`,TWN:`想活命就乖乖滾到一邊去！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`넘어가고 싶다면……`,JPN:`通りたくば……`,ENG:`You can only take her...`,TWN:`想越過我的話……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`덤벼라.`,JPN:`かかってこい。`,ENG:`over my dead body.`,TWN:`就儘管試試看！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아, 그래.`,JPN:`あ、そう。`,ENG:`Sure.`,TWN:`喔，好吧。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`그럼 소원대로 죽여 줄게!`,JPN:`じゃあ、お望みどおり殺してあげる！`,ENG:`Then I'll give you what you wish.`,TWN:`那我就如你所願殺光你們！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`하압!`,JPN:`はあっ！`,ENG:`Haargh!`,TWN:`呼呼！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK`,slots:{L:null,C:null,R:null}}}];export{e as default};